const t=JSON.parse('{"key":"v-1c1fde84","path":"/docs/algorithm/1.%E6%9C%89%E9%99%90%E7%8A%B6%E6%80%81%E6%9C%BA.html","title":"有限状态自动机","lang":"zh-CN","frontmatter":{"icon":"circ","cover":"/assets/images/cover3.jpg","description":"有限状态自动机 确定有限状态自动机（以下简称「自动机」）是一类计算模型。它包含一系列状态，这些状态中： 有一种特殊的状态，被称作「初始状态」。 还有一系列状态被称为「接受状态」，它们组成了一个特殊的集合。其中，一个状态可能既是「初始状态」，也是「接受状态」。 起初，这个自动机处于「初始状态」。随后，它顺序地读取字符串中的每一个字符，并根据当前状态和读入的字符，按照某个事先约定好的「转移规则」，从当前状态转移到下一个状态；当状态转移完成后，它就读取下一个字符。当字符串全部读取完毕后，如果自动机处于某个「接受状态」，则判定该字符串「被接受」；否则，判定该字符串「被拒绝」。","head":[["meta",{"property":"og:url","content":"https://wqmslx.github.io/docs/algorithm/1.%E6%9C%89%E9%99%90%E7%8A%B6%E6%80%81%E6%9C%BA.html"}],["meta",{"property":"og:site_name","content":"纸飞机的博客"}],["meta",{"property":"og:title","content":"有限状态自动机"}],["meta",{"property":"og:description","content":"有限状态自动机 确定有限状态自动机（以下简称「自动机」）是一类计算模型。它包含一系列状态，这些状态中： 有一种特殊的状态，被称作「初始状态」。 还有一系列状态被称为「接受状态」，它们组成了一个特殊的集合。其中，一个状态可能既是「初始状态」，也是「接受状态」。 起初，这个自动机处于「初始状态」。随后，它顺序地读取字符串中的每一个字符，并根据当前状态和读入的字符，按照某个事先约定好的「转移规则」，从当前状态转移到下一个状态；当状态转移完成后，它就读取下一个字符。当字符串全部读取完毕后，如果自动机处于某个「接受状态」，则判定该字符串「被接受」；否则，判定该字符串「被拒绝」。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://wqmslx.github.io/assets/images/cover3.jpg"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-07-17T08:14:22.000Z"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:image:alt","content":"有限状态自动机"}],["meta",{"property":"article:author","content":"纸飞机"}],["meta",{"property":"article:modified_time","content":"2023-07-17T08:14:22.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"有限状态自动机\\",\\"image\\":[\\"https://wqmslx.github.io/assets/images/cover3.jpg\\"],\\"dateModified\\":\\"2023-07-17T08:14:22.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"纸飞机\\",\\"url\\":\\"https://wqmslx.github.io\\"}]}"]]},"headers":[{"level":2,"title":"剑指 Offer 20. 表示数值的字符串","slug":"剑指-offer-20-表示数值的字符串","link":"#剑指-offer-20-表示数值的字符串","children":[{"level":3,"title":"问题描述","slug":"问题描述","link":"#问题描述","children":[]},{"level":3,"title":"思路与算法","slug":"思路与算法","link":"#思路与算法","children":[]}]}],"git":{"createdTime":1689581662000,"updatedTime":1689581662000,"contributors":[{"name":"wangqiming","email":"1358632259@qq.com","commits":1}]},"readingTime":{"minutes":3.56,"words":1069},"filePathRelative":"docs/algorithm/1.有限状态机.md","localizedDate":"2023年7月17日","excerpt":"<h1> 有限状态自动机</h1>\\n<p>确定有限状态自动机（以下简称「自动机」）是一类计算模型。它包含一系列状态，这些状态中：<br>\\n有一种特殊的状态，被称作「初始状态」。<br>\\n还有一系列状态被称为「接受状态」，它们组成了一个特殊的集合。其中，一个状态可能既是「初始状态」，也是「接受状态」。<br>\\n起初，这个自动机处于「初始状态」。随后，它顺序地读取字符串中的每一个字符，并根据当前状态和读入的字符，按照某个事先约定好的「转移规则」，从当前状态转移到下一个状态；当状态转移完成后，它就读取下一个字符。当字符串全部读取完毕后，如果自动机处于某个「接受状态」，则判定该字符串「被接受」；否则，判定该字符串「被拒绝」。</p>","autoDesc":true}');export{t as data};
